1	// Edge function: apify-webhook (US-016, US-017)
2	//
3	// Contract:
4	//   POST (headers include X-Apify-Webhook-Secret)
5	//     body: {
6	//       eventType: 'ACTOR.RUN.SUCCEEDED'|'ACTOR.RUN.FAILED'
7	//                 |'ACTOR.RUN.TIMED_OUT'|'ACTOR.RUN.ABORTED',
8	//       resource: { id, defaultDatasetId, status, actId },
9	//       social_link_id, scrape_mode, run_id,
10	//       status?, apify_finished_at?, dataset_id?,   // injected via payloadTemplate
11	//     }
12	//     → 200 { ok: true, inserted?: bool, duplicate?: bool, skipped?: 'unsupported_scrape_mode' }
13	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
14	//     → 401 { error: 'UNAUTHORIZED' }
15	//     → 405 { error: 'METHOD_NOT_ALLOWED' }
16	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'APIFY_FETCH_ERROR' }
17	//
18	// Auth: no JWT — webhook-auth via constant-time compare of the
19	//   X-Apify-Webhook-Secret header against env APIFY_WEBHOOK_SECRET or
20	//   APIFY_WEBHOOK_SECRET_PREVIOUS (dual-secret rotation window per
21	//   docs/tech-architecture.md §3g). Deploy with --no-verify-jwt.
22	//
23	// Idempotency: each scrape_mode branch dispatches to its own persistence RPC
24	//   (public.apify_webhook_persist_tiktok_profile, ..._ig_details) that inserts
25	//   one metric_snapshots row keyed on apify_run_id; the partial unique index
26	//   metric_snapshots_run_uniq makes the second webhook for the same run a
27	//   no-op. Each RPC returns {inserted, duplicate, snapshot_id?}.
28	//
29	// Scope (US-016, US-017): tiktok_profile + ig_details branches. ig_posts
30	//   returns 200 { skipped: 'unsupported_scrape_mode' } so Apify doesn't retry;
31	//   that branch ships with US-018.
32	//
33	// Pre-refreshing-row note (US-020 handoff): each RPC currently INSERTs (never
34	//   UPDATEs), so assumes no existing snapshot row carries this apify_run_id.
35	//   US-020 (auth-signup-creator Apify dispatch) will pre-create snapshots in
36	//   status='refreshing' before the webhook arrives — at that point the RPC
37	//   (or the denorm trigger) must be extended to UPDATE-then-denorm. See the
38	//   spec-gap note in the us_016_apify_webhook_persist_rpc migration.
39	
40	import { createClient } from "npm:@supabase/supabase-js@2";
41	import { corsHeaders } from "../_shared/cors.ts";
42	
43	const APIFY_API_BASE = "https://api.apify.com/v2";
44	
45	interface WebhookBody {
46	  eventType?: unknown;
47	  resource?: unknown;
48	  social_link_id?: unknown;
49	  scrape_mode?: unknown;
50	  run_id?: unknown;
51	  status?: unknown;
52	  apify_finished_at?: unknown;
53	  dataset_id?: unknown;
54	}
55	
56	interface ApifyResource {
57	  id: string;
58	  defaultDatasetId: string;
59	  status: string;
60	  actId: string;
61	}
62	
63	interface TikTokAuthorMeta {
64	  fans?: number;
65	  following?: number;
66	  heart?: number;
67	  video?: number;
68	  verified?: boolean;
69	}
70	
71	interface TikTokItem {
72	  authorMeta?: TikTokAuthorMeta;
73	  playCount?: number;
74	}
75	
76	interface InstagramDetailsItem {
77	  followersCount?: number;
78	  followsCount?: number;
79	  postsCount?: number;
80	  verified?: boolean;
81	}
82	
83	type MetricStatus = "fresh" | "failed";
84	
85	type ScrapeMode = "tiktok_profile" | "ig_details" | "ig_posts";
86	
87	interface PersistResult {
88	  inserted?: boolean;
89	  duplicate?: boolean;
90	  snapshot_id?: string;
91	}
92	
93	const SUCCEEDED_EVENT = "ACTOR.RUN.SUCCEEDED";
94	const TERMINAL_EVENT_TYPES = new Set([
95	  SUCCEEDED_EVENT,
96	  "ACTOR.RUN.FAILED",
97	  "ACTOR.RUN.TIMED_OUT",
98	  "ACTOR.RUN.ABORTED",
99	]);
100	
101	function jsonResponse(status: number, body: unknown): Response {
102	  return new Response(JSON.stringify(body), {
103	    status,
104	    headers: { ...corsHeaders, "Content-Type": "application/json" },
105	  });
106	}
107	
108	function isNonEmptyString(value: unknown): value is string {
109	  return typeof value === "string" && value.length > 0;
110	}
111	
112	// Constant-time string compare. Lengths are compared first; when lengths
113	// differ we still iterate over the longer string to keep timing flat.
114	function timingSafeEqual(a: string, b: string): boolean {
115	  const enc = new TextEncoder();
116	  const aBytes = enc.encode(a);
117	  const bBytes = enc.encode(b);
118	  const len = Math.max(aBytes.length, bBytes.length);
119	  let diff = aBytes.length ^ bBytes.length;
120	  for (let i = 0; i < len; i++) {
121	    const ac = i < aBytes.length ? aBytes[i] : 0;
122	    const bc = i < bBytes.length ? bBytes[i] : 0;
123	    diff |= ac ^ bc;
124	  }
125	  return diff === 0;
126	}
127	
128	function verifyWebhookSecret(req: Request): boolean {
129	  const provided = req.headers.get("x-apify-webhook-secret");
130	  if (!isNonEmptyString(provided)) return false;
131	  const current = Deno.env.get("APIFY_WEBHOOK_SECRET") ?? "";
132	  const previous = Deno.env.get("APIFY_WEBHOOK_SECRET_PREVIOUS") ?? "";
133	  if (!current && !previous) return false;
134	  // Both comparisons always run (no short-circuit) so an attacker who has
135	  // recovered `current` can't time-distinguish whether `previous` is set.
136	  const matchCurrent = current ? timingSafeEqual(provided, current) : false;
137	  const matchPrevious = previous ? timingSafeEqual(provided, previous) : false;
138	  return matchCurrent || matchPrevious;
139	}
140	
141	function validResource(value: unknown): value is ApifyResource {
142	  if (!value || typeof value !== "object") return false;
143	  const r = value as Record<string, unknown>;
144	  return (
145	    isNonEmptyString(r.id) &&
146	    isNonEmptyString(r.defaultDatasetId) &&
147	    isNonEmptyString(r.status) &&
148	    isNonEmptyString(r.actId)
149	  );
150	}
151	
152	function meanPlayCount(items: TikTokItem[]): number | null {
153	  const slice = items.slice(0, 10);
154	  const views: number[] = [];
155	  for (const it of slice) {
156	    if (typeof it?.playCount === "number" && Number.isFinite(it.playCount)) {
157	      views.push(it.playCount);
158	    }
159	  }
160	  if (views.length === 0) return null;
161	  const sum = views.reduce((acc, n) => acc + n, 0);
162	  return Math.round(sum / views.length);
163	}
164	
165	async function fetchDatasetItems(
166	  datasetId: string,
167	  apifyKey: string,
168	): Promise<unknown[]> {
169	  const url = new URL(`${APIFY_API_BASE}/datasets/${datasetId}/items`);
170	  url.searchParams.set("token", apifyKey);
171	  url.searchParams.set("clean", "1");
172	  const res = await fetch(url.toString(), { method: "GET" });
173	  if (!res.ok) {
174	    // Don't include res body — Apify can echo the token-carrying URL inside
175	    // error payloads, and this lands in edge-function logs.
176	    throw new Error(
177	      `Apify dataset '${datasetId}' fetch failed: ${res.status} ${res.statusText}`,
178	    );
179	  }
180	  const items = await res.json();
181	  if (!Array.isArray(items)) {
182	    throw new Error(`Apify dataset '${datasetId}' returned non-array payload`);
183	  }
184	  return items;
185	}
186	
187	Deno.serve(async (req) => {
188	  if (req.method === "OPTIONS") {
189	    return new Response(null, { status: 204, headers: corsHeaders });
190	  }
191	  if (req.method !== "POST") {
192	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
193	  }
194	
195	  if (!verifyWebhookSecret(req)) {
196	    return jsonResponse(401, { error: "UNAUTHORIZED" });
197	  }
198	
199	  let body: WebhookBody;
200	  try {
201	    body = await req.json();
202	  } catch {
203	    return jsonResponse(400, { error: "INVALID_JSON" });
204	  }
205	
206	  if (
207	    !isNonEmptyString(body.eventType) ||
208	    !TERMINAL_EVENT_TYPES.has(body.eventType) ||
209	    !validResource(body.resource) ||
210	    !isNonEmptyString(body.social_link_id) ||
211	    !isNonEmptyString(body.scrape_mode) ||
212	    !isNonEmptyString(body.run_id)
213	  ) {
214	    return jsonResponse(400, { error: "INVALID_REQUEST" });
215	  }
216	
217	  const scrapeMode = body.scrape_mode as ScrapeMode;
218	  if (scrapeMode !== "tiktok_profile" && scrapeMode !== "ig_details") {
219	    // ig_posts is wired in US-018; return 200 so Apify does not retry. The
220	    // social_link_id is intentionally not logged here — the row will still be
221	    // stuck 'refreshing' until the fail-stuck-refreshing cron janitor
222	    // (docs/tech-architecture.md §15) flips it to 'failed'.
223	    return jsonResponse(200, { ok: true, skipped: "unsupported_scrape_mode" });
224	  }
225	
226	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
227	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
228	  if (!supabaseUrl || !serviceRoleKey) {
229	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
230	  }
231	
232	  const resource = body.resource as ApifyResource;
233	  const runId = body.run_id;
234	  const socialLinkId = body.social_link_id;
235	  const fetchedAt = isNonEmptyString(body.apify_finished_at)
236	    ? body.apify_finished_at
237	    : new Date().toISOString();
238	
239	  let nextStatus: MetricStatus;
240	  let items: unknown[] | null = null;
241	  let rawPayload: unknown = null;
242	  let errorMessage: string | null = null;
243	
244	  if (body.eventType === SUCCEEDED_EVENT) {
245	    const apifyKey = Deno.env.get("APIFY_KEY");
246	    if (!apifyKey) {
247	      return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
248	    }
249	    try {
250	      items = await fetchDatasetItems(resource.defaultDatasetId, apifyKey);
251	    } catch (err) {
252	      console.error("apify dataset fetch failed", {
253	        run_id: runId,
254	        dataset_id: resource.defaultDatasetId,
255	        error: err instanceof Error ? err.message : String(err),
256	      });
257	      return jsonResponse(500, { error: "APIFY_FETCH_ERROR" });
258	    }
259	    rawPayload = items;
260	    nextStatus = "fresh";
261	  } else {
262	    nextStatus = "failed";
263	    errorMessage = `apify_${body.eventType.toLowerCase().replace(/\./g, "_")}`;
264	    rawPayload = { resource, eventType: body.eventType };
265	  }
266	
267	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
268	    auth: { persistSession: false, autoRefreshToken: false },
269	  });
270	
271	  let result: PersistResult | null = null;
272	  let rpcError: { code?: string; message?: string } | null = null;
273	  let rpcName: string;
274	
275	  if (scrapeMode === "tiktok_profile") {
276	    rpcName = "apify_webhook_persist_tiktok_profile";
277	    let followerCount: number | null = null;
278	    let followingCount: number | null = null;
279	    let totalLikes: number | null = null;
280	    let videoCount: number | null = null;
281	    let avgViewsLast10: number | null = null;
282	    let isVerified: boolean | null = null;
283	    if (items) {
284	      const tiktokItems = items as TikTokItem[];
285	      const first = tiktokItems[0];
286	      const authorMeta = first?.authorMeta;
287	      if (authorMeta) {
288	        followerCount = typeof authorMeta.fans === "number" ? authorMeta.fans : null;
289	        followingCount = typeof authorMeta.following === "number"
290	          ? authorMeta.following
291	          : null;
292	        totalLikes = typeof authorMeta.heart === "number" ? authorMeta.heart : null;
293	        videoCount = typeof authorMeta.video === "number" ? authorMeta.video : null;
294	        isVerified = typeof authorMeta.verified === "boolean"
295	          ? authorMeta.verified
296	          : null;
297	      }
298	      avgViewsLast10 = meanPlayCount(tiktokItems);
299	    }
300	    const { data, error } = await supabase.rpc(
301	      "apify_webhook_persist_tiktok_profile",
302	      {
303	        p_run_id: runId,
304	        p_social_link_id: socialLinkId,
305	        p_status: nextStatus,
306	        p_fetched_at: fetchedAt,
307	        p_follower_count: followerCount,
308	        p_following_count: followingCount,
309	        p_total_likes: totalLikes,
310	        p_video_count: videoCount,
311	        p_avg_views_last_10: avgViewsLast10,
312	        p_is_verified: isVerified,
313	        p_raw_payload: rawPayload as never,
314	        p_error_message: errorMessage,
315	      },
316	    );
317	    result = data as PersistResult | null;
318	    rpcError = error;
319	  } else {
320	    // ig_details — details[0] yields follower/following/posts/verified per
321	    // docs/tech-architecture.md §3c. avg_views_last_10 is owned by ig_posts,
322	    // so leave it NULL here; the denorm trigger for ig_details updates only
323	    // instagram_follower_count + instagram_media_count + metrics_fetched_at.
324	    rpcName = "apify_webhook_persist_ig_details";
325	    let followerCount: number | null = null;
326	    let followingCount: number | null = null;
327	    let mediaCount: number | null = null;
328	    let isVerified: boolean | null = null;
329	    if (items) {
330	      const igItems = items as InstagramDetailsItem[];
331	      const first = igItems[0];
332	      if (first) {
333	        followerCount = typeof first.followersCount === "number"
334	          ? first.followersCount
335	          : null;
336	        followingCount = typeof first.followsCount === "number"
337	          ? first.followsCount
338	          : null;
339	        mediaCount = typeof first.postsCount === "number"
340	          ? first.postsCount
341	          : null;
342	        isVerified = typeof first.verified === "boolean"
343	          ? first.verified
344	          : null;
345	      }
346	    }
347	    const { data, error } = await supabase.rpc(
348	      "apify_webhook_persist_ig_details",
349	      {
350	        p_run_id: runId,
351	        p_social_link_id: socialLinkId,
352	        p_status: nextStatus,
353	        p_fetched_at: fetchedAt,
354	        p_follower_count: followerCount,
355	        p_following_count: followingCount,
356	        p_media_count: mediaCount,
357	        p_is_verified: isVerified,
358	        p_raw_payload: rawPayload as never,
359	        p_error_message: errorMessage,
360	      },
361	    );
362	    result = data as PersistResult | null;
363	    rpcError = error;
364	  }
365	
366	  if (rpcError) {
367	    console.error(`${rpcName} rpc error`, {
368	      run_id: runId,
369	      code: rpcError.code,
370	      message: rpcError.message,
371	    });
372	    return jsonResponse(500, { error: "DB_ERROR" });
373	  }
374	
375	  return jsonResponse(200, {
376	    ok: true,
377	    inserted: result?.inserted === true,
378	    duplicate: result?.duplicate === true,
379	  });
380	});
381

