1	// Edge function: apify-webhook (US-016, US-017)
2	//
3	// Contract:
4	//   POST (headers include X-Apify-Webhook-Secret)
5	//     body: {
6	//       eventType: 'ACTOR.RUN.SUCCEEDED'|'ACTOR.RUN.FAILED'
7	//                 |'ACTOR.RUN.TIMED_OUT'|'ACTOR.RUN.ABORTED',
8	//       resource: { id, defaultDatasetId, status, actId },
9	//       social_link_id, scrape_mode, run_id,
10	//       status?, apify_finished_at?, dataset_id?,   // injected via payloadTemplate
11	//     }
12	//     → 200 { ok: true, inserted?: bool, duplicate?: bool, skipped?: 'unsupported_scrape_mode' }
13	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
14	//     → 401 { error: 'UNAUTHORIZED' }
15	//     → 405 { error: 'METHOD_NOT_ALLOWED' }
16	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'APIFY_FETCH_ERROR' }
17	//
18	// Auth: no JWT — webhook-auth via constant-time compare of the
19	//   X-Apify-Webhook-Secret header against env APIFY_WEBHOOK_SECRET or
20	//   APIFY_WEBHOOK_SECRET_PREVIOUS (dual-secret rotation window per
21	//   docs/tech-architecture.md §3g). Deploy with --no-verify-jwt.
22	//
23	// Idempotency: each scrape_mode branch dispatches to its own persistence RPC
24	//   (public.apify_webhook_persist_tiktok_profile, ..._ig_details) that inserts
25	//   one metric_snapshots row keyed on apify_run_id; the partial unique index
26	//   metric_snapshots_run_uniq makes the second webhook for the same run a
27	//   no-op. Each RPC returns {inserted, duplicate, snapshot_id?}.
28	//
29	// Scope (US-016, US-017): tiktok_profile + ig_details branches. ig_posts
30	//   returns 200 { skipped: 'unsupported_scrape_mode' } so Apify doesn't retry;
31	//   that branch ships with US-018.
32	//
33	// Pre-refreshing-row note (US-020 handoff): each RPC currently INSERTs (never
34	//   UPDATEs), so assumes no existing snapshot row carries this apify_run_id.
35	//   US-020 (auth-signup-creator Apify dispatch) will pre-create snapshots in
36	//   status='refreshing' before the webhook arrives — at that point the RPC
37	//   (or the denorm trigger) must be extended to UPDATE-then-denorm. See the
38	//   spec-gap note in the us_016_apify_webhook_persist_rpc migration.
39	
40	import { createClient } from "npm:@supabase/supabase-js@2";
41	import { corsHeaders } from "../_shared/cors.ts";
42	
43	const APIFY_API_BASE = "https://api.apify.com/v2";
44	
45	interface WebhookBody {
46	  eventType?: unknown;
47	  resource?: unknown;
48	  social_link_id?: unknown;
49	  scrape_mode?: unknown;
50	  run_id?: unknown;
51	  status?: unknown;
52	  apify_finished_at?: unknown;
53	  dataset_id?: unknown;
54	}
55	
56	interface ApifyResource {
57	  id: string;
58	  defaultDatasetId: string;
59	  status: string;
60	  actId: string;
61	}
62	
63	interface TikTokAuthorMeta {
64	  fans?: number;
65	  following?: number;
66	  heart?: number;
67	  video?: number;
68	  verified?: boolean;
69	}
70	
71	interface TikTokItem {
72	  authorMeta?: TikTokAuthorMeta;
73	  playCount?: number;
74	}
75	
76	interface InstagramDetailsItem {
77	  followersCount?: number;
78	  followsCount?: number;
79	  postsCount?: number;
80	  verified?: boolean;
81	}
82	
83	type MetricStatus = "fresh" | "failed";
84	
85	type ScrapeMode = "tiktok_profile" | "ig_details" | "ig_posts";
86	
87	interface PersistResult {
88	  inserted?: boolean;
89	  duplicate?: boolean;
90	  snapshot_id?: string;
91	}
92	
93	const SUCCEEDED_EVENT = "ACTOR.RUN.SUCCEEDED";
94	const TERMINAL_EVENT_TYPES = new Set([
95	  SUCCEEDED_EVENT,
96	  "ACTOR.RUN.FAILED",
97	  "ACTOR.RUN.TIMED_OUT",
98	  "ACTOR.RUN.ABORTED",
99	]);
100	
101	function jsonResponse(status: number, body: unknown): Response {
102	  return new Response(JSON.stringify(body), {
103	    status,
104	    headers: { ...corsHeaders, "Content-Type": "application/json" },
105	  });
106	}
107	
108	function isNonEmptyString(value: unknown): value is string {
109	  return typeof value === "string" && value.length > 0;
110	}
111	
112	// Constant-time string compare. Lengths are compared first; when lengths
113	// differ we still iterate over the longer string to keep timing flat.
114	function timingSafeEqual(a: string, b: string): boolean {
115	  const enc = new TextEncoder();
116	  const aBytes = enc.encode(a);
117	  const bBytes = enc.encode(b);
118	  const len = Math.max(aBytes.length, bBytes.length);
119	  let diff = aBytes.length ^ bBytes.length;
120	  for (let i = 0; i < len; i++) {
