1	// Edge function: apify-webhook (US-016, US-017, US-018)
2	//
3	// Contract:
4	//   POST (headers include X-Apify-Webhook-Secret)
5	//     body: {
6	//       eventType: 'ACTOR.RUN.SUCCEEDED'|'ACTOR.RUN.FAILED'
7	//                 |'ACTOR.RUN.TIMED_OUT'|'ACTOR.RUN.ABORTED',
8	//       resource: { id, defaultDatasetId, status, actId },
9	//       social_link_id, scrape_mode, run_id,
10	//       status?, apify_finished_at?, dataset_id?,   // injected via payloadTemplate
11	//     }
12	//     → 200 { ok: true, inserted?: bool, duplicate?: bool, skipped?: 'unsupported_scrape_mode' }
13	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
14	//     → 401 { error: 'UNAUTHORIZED' }
15	//     → 405 { error: 'METHOD_NOT_ALLOWED' }
16	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'APIFY_FETCH_ERROR' }
17	//
18	// Auth: no JWT — webhook-auth via constant-time compare of the
19	//   X-Apify-Webhook-Secret header against env APIFY_WEBHOOK_SECRET or
20	//   APIFY_WEBHOOK_SECRET_PREVIOUS (dual-secret rotation window per
21	//   docs/tech-architecture.md §3g). Deploy with --no-verify-jwt.
22	//
23	// Idempotency: each scrape_mode branch dispatches to its own persistence RPC
24	//   (public.apify_webhook_persist_tiktok_profile, ..._ig_details, ..._ig_posts)
25	//   that inserts one metric_snapshots row keyed on apify_run_id; the partial
26	//   unique index metric_snapshots_run_uniq makes the second webhook for the
27	//   same run a no-op. Each RPC returns {inserted, duplicate, snapshot_id?}.
28	//
29	// Scope (US-016, US-017, US-018): tiktok_profile, ig_details, and ig_posts
30	//   branches are all live. Any other scrape_mode value returns 200
31	//   { skipped: 'unsupported_scrape_mode' } so Apify does not retry.
32	//
33	// Pre-refreshing-row note (US-020 handoff): each RPC currently INSERTs (never
34	//   UPDATEs), so assumes no existing snapshot row carries this apify_run_id.
35	//   US-020 (auth-signup-creator Apify dispatch) will pre-create snapshots in
36	//   status='refreshing' before the webhook arrives — at that point the RPC
37	//   (or the denorm trigger) must be extended to UPDATE-then-denorm. See the
38	//   spec-gap note in the us_016_apify_webhook_persist_rpc migration.
39	
40	import { createClient } from "npm:@supabase/supabase-js@2";
