    !isNonEmptyString(body.eventType) ||
    !TERMINAL_EVENT_TYPES.has(body.eventType) ||
    !validResource(body.resource) ||
    !isNonEmptyString(body.social_link_id) ||
    !isNonEmptyString(body.scrape_mode) ||
    !isNonEmptyString(body.run_id)
